Code.Terraform:
```hcl
resource "oci_events_rule" "<example_resource_name>" {
  compartment_id = "<example_resource_id>"
  display_name   = "<example_resource_name>"
  is_enabled     = true

  condition = jsonencode({
    eventType = [
      "com.oraclecloud.identitycontrolplane.addidpgroupmapping", # critical: monitor IdP group mapping add
      "com.oraclecloud.identitycontrolplane.removeidpgroupmapping", # critical: monitor IdP group mapping remove
      "com.oraclecloud.identitycontrolplane.updateidpgroupmapping"  # critical: monitor IdP group mapping update
    ]
  })

  actions {
    actions {
      action_type = "ONS"                       # critical: adds notification action
      topic_id    = "<example_resource_id>"     # critical: ONS topic to notify
      is_enabled  = true
    }
  }
}
```
